import { GoogleGenAI, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

// Helper function to convert a File object to a base64 string
const fileToGenerativePart = (file: File): Promise<{inlineData: {data: string, mimeType: string}}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            if (typeof reader.result === 'string') {
                const base64Data = reader.result.split(',')[1];
                resolve({
                    inlineData: {
                        data: base64Data,
                        mimeType: file.type,
                    },
                });
            } else {
                reject(new Error("Failed to read file as data URL."));
            }
        };
        reader.onerror = (error) => reject(error);
    });
};

export const generateSpeech = async (text: string, voiceName: string, language: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: voiceName },
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) throw new Error("No audio data returned.");
        return base64Audio;
    } catch (error) {
        const detailedMessage = error instanceof Error ? error.message : "Unknown error";
        throw new Error(`TTS Error: ${detailedMessage}`);
    }
};

export const generateSummary = async (text: string, targetLanguage: string): Promise<string> => {
    try {
        const prompt = `Analise profundamente este texto e crie um resumo executivo estruturado em ${targetLanguage}. Identifique os pontos chave, o tom do autor e as conclusões principais.\n\nTexto:\n${text}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // Usando o modelo Pro para máxima qualidade
            contents: prompt,
            config: {
                thinkingConfig: { thinkingBudget: 4000 }, // Ativando o modo de raciocínio
                tools: [{ googleSearch: {} }] // Permite que o AI valide fatos do texto com o Google
            }
        });
        return response.text || "Não foi possível gerar o resumo.";
    } catch (error) {
        console.error("Summary error:", error);
        throw new Error(`Erro no resumo: ${error instanceof Error ? error.message : "Falha na API"}`);
    }
};

export const translateText = async (text: string, targetLanguage: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash 3 para tradução ultra-rápida
            contents: `Traduza para ${targetLanguage} mantendo o tom original. Retorne APENAS a tradução:\n\n${text}`,
        });
        return response.text || text;
    } catch (error) {
        throw new Error("Erro na tradução.");
    }
}

export const extractTextFromImage = async (imageFile: File): Promise<string> => {
    try {
        const imagePart = await fileToGenerativePart(imageFile);
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash 3 tem visão superior
            contents: { parts: [imagePart, { text: "Extraia todo o texto desta imagem fielmente." }] },
        });
        return response.text || "";
    } catch (error) {
        throw new Error("Erro no OCR da imagem.");
    }
};

export const fetchArticleContent = async (url: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Acesse e extraia o conteúdo principal deste artigo (ignore menus/anúncios): ${url}`,
            config: {
                tools: [{ googleSearch: {} }] // Usa a busca para garantir que pega o conteúdo mais atual/correto
            }
        });
        return response.text || "";
    } catch (error) {
        throw new Error("Erro ao acessar URL.");
    }
};

